import Foundation
import Hummingbird
import JWTKit
import Logging
import OpenAPIHummingbird
import ShapeTreeClient

// MARK: - Route setup

/// Creates a Hummingbird router with the ShapeTree API handlers registered.
///
/// The handler is an `APIProtocol` implementation whose request/response types
/// are generated by `swift-openapi-generator` from `openapi.yaml`.
func buildRoutes(
  store: SessionStore,
  journalService: JournalService,
  journalQuery: JournalQueryService,
  jwtKeys: JWTKeyCollection,
  log: Logger,
  defaultOllamaURL: String = "http://127.0.0.1:11434",
  agentModel: String = "gemma4:e2b",
  systemPrompt: String = "You are a helpful coding assistant.",
  bearerToken: String? = nil,
  contextWindow: Int = 131_072,
  contextWindowThreshold: Double = 0.85
) -> Router<BasicRequestContext> {
  let router = Router(context: BasicRequestContext.self)

  router.add(middleware: ShapeTreeJWTAuthMiddleware(keys: jwtKeys))

  let handler = ShapeTreeHandler(
    store: store,
    journalService: journalService,
    journalQuery: journalQuery,
    log: log,
    defaultOllamaURL: defaultOllamaURL,
    agentModel: agentModel,
    systemPrompt: systemPrompt,
    bearerToken: bearerToken,
    contextWindow: contextWindow,
    contextWindowThreshold: contextWindowThreshold
  )

  try! handler.registerHandlers(on: router)
  return router
}
